  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  import sailpoint.api.ObjectUtil;
  import sailpoint.object.ApprovalItem;
  import sailpoint.object.ApprovalSet;
  import sailpoint.object.Bundle;
  import sailpoint.object.Application;
  import sailpoint.object.Filter;
  import sailpoint.object.Identity;
  import sailpoint.object.Custom;
  import sailpoint.object.ManagedAttribute;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.WorkItem;
  import sailpoint.object.Workflow;
  import sailpoint.object.Workflow.Approval;
  import sailpoint.tools.Util;


  /**
		 * Lists all the members of given workgroup
		 * @param wg
		 * @return list of workgroup members names
		 */
  private List getWgMembers(Identity wg) {
    String METHOD_NAME = "getWgMembers";
    logger.debug("Entering " +METHOD_NAME);
    List wgMembers = new ArrayList();
    Iterator members = ObjectUtil.getWorkgroupMembers(context, wg, null);

    while (members.hasNext()) {
      Identity identityCube = (Identity)(members.next()[0]);
      String name = identityCube.getName();
      if (!identityCube.isInactive()) {
        wgMembers.add(name);
      }
    }

    Util.flushIterator(members);
    logger.debug("Exiting " +METHOD_NAME);
    return wgMembers;
  }

  /**
		 * Method to get ministry based backup workgroup from the custom object, based on the identity name.
		 * @param String identityName
		 * @return String ministry workgroup name
		 */
  private String getMinistryWorkgroupName( String identityName ) {
    String METHOD_NAME = "getMinistryWorkgroupName";
    String OPERATIONS_WORKGROUP = "IDM Team";

    logger.debug("Entering " + METHOD_NAME);

    Identity idn = context.getObjectByName(Identity.class, identityName);
    Custom accessRequestCustom = context.getObjectByName(Custom.class, "Ascension-Custom-AccessRequest");

    String ministryName = null;
    String approvingWorkgroup = null;

    logger.debug("Evaluating ministry based workgroup for: " + identityName);
    if (idn != null && accessRequestCustom != null && Util.isNotNullOrEmpty(idn.getStringAttribute("ministry")) ) {
      ministryName = idn.getStringAttribute("ministry");

      if (Util.isNotNullOrEmpty(ministryName) && accessRequestCustom.get("MinistryApprovalMapping") != null) {
        Map ministryWorkgroupMap = accessRequestCustom.get("MinistryApprovalMapping");
        approvingWorkgroup = ministryWorkgroupMap.get(ministryName);
        if (approvingWorkgroup == null) {
          approvingWorkgroup = accessRequestCustom.get("DefaultWorkgroup");
        }
      }
    }

    logger.debug("Exiting " + METHOD_NAME);

    //comment decache //context.decache(accessRequestCustom);
    if (Util.isNotNullOrEmpty(approvingWorkgroup))
      return approvingWorkgroup;
    else
      return OPERATIONS_WORKGROUP;
  }


  /**
		 * Lists all the members of given workgroup as per below conditions
		 * if requestee is member of wg, then instead of requestee add requestee's manager as member of wg
		 * if any of the member of wg is inactive, then instead of that member add member's manager as member of wg
		 * @param wg
		 * @return list of workgroup members names
		 */
  private List getCustomWgMembers(Identity wg, String identityName) {
    String METHOD_NAME = "getCustomWgMembers";
    logger.debug("Entering " +METHOD_NAME);
    List wgMembers = new ArrayList();
    Iterator members = ObjectUtil.getWorkgroupMembers(context, wg, null);

    while (members.hasNext()) {
      Identity identityCube = (Identity)(members.next()[0]);
      String name = identityCube.getName();

      if(name.equals(identityName) || identityCube.isInactive()) {
        Identity thisMemberMgr = identityCube.getManager();

        if(thisMemberMgr != null) {
          wgMembers.add(thisMemberMgr.getName());
        }
      } else {	
        wgMembers.add(name);
      }	
    }

    Util.flushIterator(members);
    logger.debug("Exiting " +METHOD_NAME);
    return wgMembers;
  }

  /**
		 * Method to check if user's manager is active
		 * @param String identityName name of the user
		 * @return boolean whether manager is present and active
		 */
  private boolean isManagerActive(String identityName) {
    String METHOD_NAME = "isManagerActive";
    logger.debug("Entering " +METHOD_NAME);
    boolean managerStatus = false;
    Identity idn = context.getObjectByName(Identity.class, identityName);
    if (idn != null && idn.getManager() != null) {
      managerStatus = !(idn.getManager().isInactive());
    }
    logger.debug("Exiting " +METHOD_NAME);
    return managerStatus;
  }

  /**
		 * Method to check if user's manager's manager is active
		 * @param String identityName name of the user
		 * @return boolean whether manager is present and active
		 */
  private boolean isManagersManagerActive(String identityName) {
    String METHOD_NAME = "isManagersManagerActive";
    logger.debug("Entering " +METHOD_NAME);
    boolean managerManagerStatus = false;
    Identity idn = context.getObjectByName(Identity.class, identityName);
    if (idn != null && idn.getManager() != null) {
      Identity userManager = idn.getManager();
      if (userManager.getManager() != null) {
        managerManagerStatus = !(userManager.getManager().isInactive());
      }
    }
    logger.debug("Exiting " +METHOD_NAME);
    return managerManagerStatus;
  }


  /**
		 * Get manager approval object
		 * @param Identity userIdentity
		 * @param String identityName
		 * @param String managerName
		 * @param ApprovalItem ai
		 * @return Approval object with manager approval
		 */
  private Approval getManagerApproval(Identity userIdentity, String identityName, String managerName, ApprovalItem ai) {
    Approval mgrApproval = new Approval();
    ApprovalSet mgrApprSet = new ApprovalSet();
    mgrApprSet.add(ai);
    if(userIdentity!=null && Util.isNotNullOrEmpty(userIdentity.getStringAttribute("contractorManager")) ){
      Identity contractorManagerIdentity = context.getObjectByName(Identity.class,userIdentity.getStringAttribute("contractorManager"));
      if(contractorManagerIdentity!=null && !contractorManagerIdentity.isInactive() && Util.isNotNullOrEmpty(contractorManagerIdentity.getStringAttribute("isContractorManager")) && "true".equalsIgnoreCase(contractorManagerIdentity.getStringAttribute("isContractorManager"))){
        mgrApproval.setOwner(contractorManagerIdentity.getName()); 
      }else{
        mgrApproval.setOwner(managerName);  
      }
      if(contractorManagerIdentity!=null){
        //comment decache //context.decache(contractorManagerIdentity);
      }
    }else{
      mgrApproval.setOwner(managerName);  
    }
    mgrApproval.setDescription("Manager Level Approval for " +userIdentity.getDisplayName()) ;
    mgrApproval.setApprovalSet(mgrApprSet);
    mgrApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
    mgrApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
    return mgrApproval;
  }




  /**
		 * Lists all the members of given workgroup as per below conditions
		 * if requestee is member of wg, then remove him as member of wg
		 * @param wg
		 * @return list of workgroup members names
		 */
  private List getWgMembersWithoutRequestee(Identity wg, String identityName) {
    String METHOD_NAME = "getWgMembersWithoutRequestee";
    logger.debug("Entering " + METHOD_NAME);
    List wgMembers = new ArrayList();
    Iterator members = ObjectUtil.getWorkgroupMembers(context, wg, null);

    while (members.hasNext()) {
      Identity identityCube = (Identity)(members.next()[0]);
      String name = identityCube.getName();

      //To exclude the requestee.
      if(!name.equals(identityName)) {
        wgMembers.add(name);
      }
    }

    Util.flushIterator(members);
    logger.debug("Exiting " +METHOD_NAME);
    return wgMembers;
  }


  /**
		 * creates a parallel approval
		 * @param selectedApprover
		 * @param ai
		 * @param identityName
		 * @param approvalLevel
		 * @return Approval
		 */
  private Approval getHighRiskApprovals(Identity selectedApprover, ApprovalItem ai, String identityName, String approvalLevel) {
    String METHOD_NAME = "getHighRiskApprovals";
    logger.debug("Entering " +METHOD_NAME);
    List allWgMembersApprovalsList = new ArrayList();

    Approval parallelApproval;
    Approval parentApprovalOfWgMem = new Workflow.Approval();
    parentApprovalOfWgMem.setMode("parallel");
    ApprovalSet identApprSet = new ApprovalSet();
    identApprSet.add(ai);

    List wgApproversList = getCustomWgMembers(selectedApprover,identityName);

    for(String wgMemberName : wgApproversList) {
      // Since all the members of wg should take action, create seperate parallel approvals for each member
      parallelApproval = new Approval();
      parallelApproval.setOwner("\"" + wgMemberName + "\"");
      parallelApproval.setApprovalSet(identApprSet.clone());
      parallelApproval.setDescription(approvalLevel +" "+ wgMemberName +" (each wg member) Approval for " +userIdentity.getDisplayName()) ;
      parallelApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
      parallelApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
      allWgMembersApprovalsList.add(parallelApproval);	
    }
    parentApprovalOfWgMem.setChildren(allWgMembersApprovalsList);
    logger.debug("Exiting " +METHOD_NAME);
    return parentApprovalOfWgMem;
  }


  /**
		 * creates a Any level approval
		 * @param selectedApprover
		 * @param ai
		 * @param identityName
		 * @param approvalLevel
		 * @return Approval
		 */
  private Approval getAnyApprovals(Identity selectedApprover, ApprovalItem ai, String identityName,String approvalLevel) {
    String METHOD_NAME = "getAnyApprovals";
    logger.debug("Entering " +METHOD_NAME);
    List allWgMembersApprovalsList = new ArrayList();
    Approval anyApproval;
    Approval parentAnyApprovalOfWgMem = new Workflow.Approval();
    parentAnyApprovalOfWgMem.setMode("any");
    ApprovalSet identApprSet = new ApprovalSet();
    identApprSet.add(ai);	

    List wgApproversList =  getWgMembersWithoutRequestee(selectedApprover,identityName);

    for(String wgMemberName : wgApproversList) {
      // Any one of the members of wg should take action
      anyApproval = new Approval();
      anyApproval.setOwner("\"" + wgMemberName + "\"");
      anyApproval.setApprovalSet(identApprSet.clone());
      anyApproval.setDescription(approvalLevel +" "+ wgMemberName +" (any wg member) Approval for " +userIdentity.getDisplayName()) ;
      anyApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
      anyApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
      allWgMembersApprovalsList.add(anyApproval);	
    }

    parentAnyApprovalOfWgMem.setChildren(allWgMembersApprovalsList);
    logger.debug("Exiting " +METHOD_NAME);
    return parentAnyApprovalOfWgMem;
  }

  /**
		 * creates a workgroup approval
		 * @param workgroup
		 * @param ai
		 * @param entApplication
		 * @param identityName
		 * @param approvalLevel
		 * @return Approval
		 */
  private Approval getWorkgroupApprovals(Identity workgroup, ApprovalItem ai, Application entApplication, String identityName, String approvalLevel) {
    String METHOD_NAME = "getWorkgroupApprovals";
    logger.debug("Entering " +METHOD_NAME);
    List wgApproversList =  getCustomWgMembers(workgroup,identityName);
    Identity userIdentity = context.getObjectByName(Identity.class, identityName);
    Approval wgApproval = new Approval();
    Identity appOwner = (entApplication == null ? null : entApplication.getOwner());
    if ( wgApproversList.size() == 0 ) {
      Identity wgOwner = workgroup.getOwner();
      if (wgOwner != null && !wgOwner.isInactive() && !wgOwner.getName().equals(identityName)) {
        ApprovalSet wgApprSet = new ApprovalSet();
        wgApprSet.add(ai);
        wgApproval.setOwner(wgOwner.getName());  
        wgApproval.setDescription(approvalLevel + " Approval for " +userIdentity.getDisplayName()) ;
        wgApproval.setApprovalSet(wgApprSet);
        wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
        wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
      } else if (appOwner != null) {
        if (appOwner.isWorkgroup()) {
          wgApproval = getAnyApprovals(appOwner, ai, identityName, approvalLevel);
        } else if ( !appOwner.isInactive() && !appOwner.getName().equals(identityName) ) {
          ApprovalSet wgApprSet = new ApprovalSet();
          wgApprSet.add(ai);
          wgApproval.setOwner(appOwner.getName());  
          wgApproval.setDescription(approvalLevel + " Approval for " +userIdentity.getDisplayName()) ;
          wgApproval.setApprovalSet(wgApprSet);
          wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
          wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
        } else {
          ApprovalSet wgApprSet = new ApprovalSet();
          wgApprSet.add(ai);
          wgApproval.setOwner(OPERATIONS_WORKGROUP);  
          wgApproval.setDescription(approvalLevel + " Approval for " +userIdentity.getDisplayName()) ;
          wgApproval.setApprovalSet(wgApprSet);
          wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
          wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
        }
      } else {
        ApprovalSet wgApprSet = new ApprovalSet();
        wgApprSet.add(ai);
        wgApproval.setOwner(OPERATIONS_WORKGROUP);  
        wgApproval.setDescription(approvalLevel + " Approval for " +userIdentity.getDisplayName()) ;
        wgApproval.setApprovalSet(wgApprSet);
        wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
        wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
      }
    } else if ( wgApproversList.contains(identityName) ) {
      wgApproval = getAnyApprovals(workgroup, ai, identityName, approvalLevel);
    } else {
      ApprovalSet wgApprSet = new ApprovalSet();
      wgApprSet.add(ai);
      wgApproval.setOwner(workgroup.getName());  
      wgApproval.setDescription(approvalLevel + " Approval for " +userIdentity.getDisplayName()) ;
      wgApproval.setApprovalSet(wgApprSet);
      wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
      wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
    }
    return wgApproval;
  }

  private boolean isPassthroughRole(Identity launcher, Bundle bundle) {

    /*
        This method is used to set approvalType to "none" when
        an Identity holding the "iamProvisionerRights" Role submits
        an Access Request for a Role originally requested via
        NARS/OAARS.
    */

    //Logic for IAM Provisioners

    import sailpoint.object.Bundle;
    import sailpoint.object.Identity;
    import sailpoint.tools.Util;

    List passthroughRoles = Util.csvToList("EHRSearch Viewer,Good Day Ascension Intranet Access (CWR only)");
    String requestedRole = bundle.getName();

    Bundle iamProvisionerRights = context.getObjectByName(Bundle.class, "iamProvisionerRights");

    if (iamProvisionerRights != null) {

      boolean isProvisioner = launcher.hasRole(iamProvisionerRights, false);

      if (isProvisioner) {

        if (Util.nullSafeContains(passthroughRoles, requestedRole)) {

          return true;

        }

      }

    }

    //Logic for Care Studio - Trusted Requesters 

    List passthroughRolesCareStudio = Util.csvToList("EHRSearch Experimenter,EHRSearch Onboarder,EHRSearch UATester,EHRSearch Viewer");

    //Get Relevant Workgroup

    Identity careStudioRequestersWg = context.getObjectByName(Identity.class, "Care Studio - Trusted Requesters");

    if (careStudioRequestersWg != null && careStudioRequestersWg.isWorkgroup()) {

      List props = new ArrayList();
      List wgMembersList = new ArrayList();

      Iterator wgMembers = ObjectUtil.getWorkgroupMembers(context, careStudioRequestersWg, props);

      while (wgMembers.hasNext()) {

        Identity currentMember = wgMembers.next()[0];

        if (currentMember != null && Util.isNotNullOrEmpty(currentMember.getName())) {

          //Add identityName of workgroup members to list

          wgMembersList.add(currentMember.getName());

        }

      }

      //Check if identityName of launcher is in wgMembersList

      if (Util.nullSafeContains(wgMembersList, launcher.getName())) {

        if (Util.nullSafeContains(passthroughRolesCareStudio, requestedRole)) {

          return true;

        }

      } 

    }

    return false;

  }


  // Logic starts from here
  static Log logger = LogFactory.getLog("rule.ApprovalAssignment.AccessRequest");

  String RULE_NAME = "Ascension-Rule-ApprovalAssignment-AccessRequest";
  logger.debug("Entering " +RULE_NAME);

  List finalApprovals = new ArrayList();
  List superApprovals = new ArrayList();
  String managerName="";
  String contractorManagerName="";
  boolean isProvisioningWorkgroup = false;

  List managerApprovalSkipList = new ArrayList();

  boolean isManagerApprovalSkip = false;

  String OPERATIONS_WORKGROUP = "IDM Team";
  String PROVISIONING_WORKGROUP = "TNNAS Provisioner Workgroup";
  Custom accessRequestCustom = context.getObjectByName(Custom.class, "Ascension-Custom-AccessRequest");
  if (accessRequestCustom != null && Util.isNotNullOrEmpty(accessRequestCustom.get("DefaultWorkgroup"))) {
    OPERATIONS_WORKGROUP = accessRequestCustom.get("DefaultWorkgroup");
    if(Util.isNotNullOrEmpty(accessRequestCustom.get("ProvisioningWorkgroup"))){
      PROVISIONING_WORKGROUP = accessRequestCustom.get("ProvisioningWorkgroup");
    }

    if(accessRequestCustom.get("ManagerApprovalSkipWorkgroup") != null && accessRequestCustom.get("ManagerApprovalSkipWorkgroup") instanceof List){
      managerApprovalSkipList = accessRequestCustom.get("ManagerApprovalSkipWorkgroup");
    }else if(accessRequestCustom.get("ManagerApprovalSkipWorkgroup") != null && accessRequestCustom.get("ManagerApprovalSkipWorkgroup") instanceof String){
      managerApprovalSkipList.add(accessRequestCustom.get("ManagerApprovalSkipWorkgroup"));
    }
  }

  Identity userIdentity = context.getObjectByName(Identity.class, identityName);
  Identity mgrCube = null;
  if(userIdentity != null) {
     mgrCube = userIdentity.getManager();

    if(mgrCube!=null)
      managerName = mgrCube.getName();

    if(Util.isNotNullOrEmpty(userIdentity.getStringAttribute("contractorManager"))){
      contractorManagerName = userIdentity.getStringAttribute("contractorManager");
    }

  }
  Identity launcherIdentity = context.getObjectByName(Identity.class, launcher);
  Identity workgroup = context.getObjectByName(Identity.class, PROVISIONING_WORKGROUP);

  if(launcherIdentity != null && workgroup != null && launcherIdentity.isInWorkGroup(workgroup)) {    
    isProvisioningWorkgroup = true;
  }

  if(launcherIdentity != null && managerApprovalSkipList!=null && !managerApprovalSkipList.isEmpty()){
    for(String skipWG : managerApprovalSkipList){
      if( Util.isNotNullOrEmpty(skipWG)){
        Identity managerApprovalSkipWG = context.getObjectByName(Identity.class, skipWG);
        if(managerApprovalSkipWG!=null){
          if( managerApprovalSkipWG != null && launcherIdentity.isInWorkGroup(managerApprovalSkipWG)) {    
            isManagerApprovalSkip = true;
            //comment decache //context.decache(managerApprovalSkipWG);
            break;
          }
          //comment decache //context.decache(managerApprovalSkipWG);
        }
      }
    }
  }
  logger.debug("mgrCube :: " +mgrCube);
  logger.debug("launcherIdentity.getId():: " +launcherIdentity.getId());
    
  if (mgrCube !=null && (launcherIdentity.getId() == mgrCube.getId())){
    logger.debug("newly added condition to check launcher is same as user manager ");
    isManagerApprovalSkip = true;//modified for approvaltype to be owner SI-1841 by SreeRadhika

  }

  // Check to make sure the list of approval is not null.  
  if(approvalSet!=null) {
    for(ApprovalItem ai : approvalSet.getItems()) {
      List customApprovals = new ArrayList();

      logger.debug("Approval item name is ::" +ai.getName() );
      logger.debug("Approval item value is ::" +ai.getValue() );
      String rName = null;
      if(ai.getValue() !=null){
        if(ai.getValue() instanceof String) {
          rName = ai.getValue().toString();
        } else {
          rName = ai.getValue().get(0).toString();
        }
      }

      String roleOrEntName = ai.getDisplayName();

      if(Util.isNotNullOrEmpty(rName) && "Role".equalsIgnoreCase(roleOrEntName)) {
        Bundle bundle = context.getObjectByName(Bundle.class, rName);

        if(bundle != null) {
          String approvalType = (String)bundle.getAttribute("approvalType");
          logger.debug("approvalType is ::" +approvalType );
          if(Util.isNullOrEmpty(approvalType)){
            approvalType = "manager";
          }
          if(isProvisioningWorkgroup || isPassthroughRole(launcherIdentity, bundle)){
            approvalType = "none";
          }

          if(Util.isNotNullOrEmpty(approvalType)) {
            List extraApprover= new ArrayList();
            String[] approvers=approvalType.split(",");
            logger.debug("Approvers are :: " +approvers);

            if(approvers!=null) {
              for(String eachApprover : approvers) {

                if(eachApprover.equalsIgnoreCase("manager") || eachApprover.equalsIgnoreCase("Default")) {
                  if (Util.nullSafeEq(launcher, managerName, false) || Util.nullSafeCaseInsensitiveEq(launcher, contractorManagerName) || isManagerApprovalSkip) {
                    continue;
                  }
                  if (Util.isNotNullOrEmpty(managerName) && isManagerActive(identityName)) {
                    Approval mgrApproval = getManagerApproval(userIdentity, identityName, managerName, ai);
                    customApprovals.add(mgrApproval);
                  } else if (isManagersManagerActive(identityName)) {
                    String mgrMgrName = "";
                    Identity userManager = userIdentity.getManager();
                    if (userManager != null && userManager.getManager() != null) {
                      mgrMgrName = userManager.getManager().getName();
                    }
                    Approval mgrMgrApproval = getManagerApproval(userIdentity, identityName, mgrMgrName, ai);
                    customApprovals.add(mgrMgrApproval);
                  } else {
                    Approval mgrApproval = new Approval();
                    ApprovalSet mgrApprSet = new ApprovalSet();
                    mgrApprSet.add(ai);
                    mgrApproval.setOwner( getMinistryWorkgroupName(identityName) );  
                    mgrApproval.setDescription("Manager Level Approval for " +userIdentity.getDisplayName()) ;
                    mgrApproval.setApprovalSet(mgrApprSet);
                    mgrApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
                    mgrApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
                    customApprovals.add(mgrApproval);
                  }
                } else if(eachApprover.equalsIgnoreCase("owner")) {
                  Identity roleOwnerCube =  bundle.getOwner();

                  if(roleOwnerCube!=null) {
                    String roleOwnerName = roleOwnerCube.getName();
                    String isRoleHighRiskForOwner = (String)bundle.getAttribute("privileged");

                    if(roleOwnerCube.isWorkgroup() && "true".equals(isRoleHighRiskForOwner)) {
                      Approval highRiskOwnerApproval = getHighRiskApprovals(roleOwnerCube,ai,identityName,"High Risk Role Owner");
                      customApprovals.add(highRiskOwnerApproval);
                    } else if(roleOwnerCube.isWorkgroup()) {
                      // For role, passing application as 'null' to bypass application owner check
                      Approval wgApproval = getWorkgroupApprovals(roleOwnerCube, ai, null, identityName, "Owner Level Approval");
                      customApprovals.add(wgApproval);
                    } else {
                      String thisRoleOwnerName = roleOwnerName;

                      if(!roleOwnerCube.isWorkgroup() && (roleOwnerCube.isInactive()) || identityName.equals(roleOwnerName)){
                        thisRoleOwnerName = OPERATIONS_WORKGROUP;
                      }												
                      Approval ownerApproval = new Approval();
                      ApprovalSet ownerApprSet = new ApprovalSet();
                      ownerApprSet.add(ai);
                      ownerApproval.setOwner(thisRoleOwnerName);  
                      ownerApproval.setDescription("Owner Level Approval for " +userIdentity.getDisplayName()) ;
                      ownerApproval.setApprovalSet(ownerApprSet);
                      ownerApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
                      ownerApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
                      customApprovals.add(ownerApproval);
                    }
                  }else{
                    //if approvalType is set to owner but if owner is null, then send the workitem to a standard wg 

                    Approval ownerApproval = new Approval();
                    ApprovalSet ownerApprSet = new ApprovalSet();
                    ownerApprSet.add(ai);
                    ownerApproval.setOwner( getMinistryWorkgroupName(identityName) );  
                    ownerApproval.setDescription("Owner Level Approval for " +userIdentity.getDisplayName()) ;
                    ownerApproval.setApprovalSet(ownerApprSet);
                    ownerApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
                    ownerApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
                    customApprovals.add(ownerApproval);

                  }
                } else if(eachApprover.equalsIgnoreCase("identity")) {
                  String approverName = (String)bundle.getAttribute("additionalApprover");

                  if(Util.isNotNullOrEmpty(approverName)) {
                    Identity selectedApprover = context.getObjectByName(Identity.class, approverName);
                    String isRoleHighRiskForAdditional = (String)bundle.getAttribute("privilegedIdentity");

                    if(selectedApprover!=null ) {
                      if(selectedApprover.isWorkgroup() && "true".equals(isRoleHighRiskForAdditional)) {
                        Approval highRiskwgApproval  = getHighRiskApprovals(selectedApprover,ai,identityName,"Role Additional Approver");
                        customApprovals.add(highRiskwgApproval);
                      } else if(selectedApprover.isWorkgroup()) {


                        List wgApproversListWithCheck = getWgMembersWithoutRequestee(selectedApprover,identityName);
                        List wgApproverList = getWgMembers(selectedApprover);

                        if(wgApproversListWithCheck.size() != wgApproverList.size()){
                          Approval identityLevelApproval = getAnyApprovals(selectedApprover,ai,identityName,"Identity/wg Level Approval");
                          customApprovals.add(identityLevelApproval);	
                        } else {
                          Approval wgApproval = new Approval();
                          ApprovalSet identApprSet = new ApprovalSet();
                          identApprSet.add(ai);
                          wgApproval.setOwner(selectedApprover.getName());								
                          wgApproval.setDescription("Identity/wg Level Approval for " +userIdentity.getDisplayName()) ;
                          wgApproval.setApprovalSet(identApprSet);
                          wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
                          wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
                          customApprovals.add(wgApproval);									
                        }
                      } else {
                        String thisOwner = selectedApprover.getName();

                        if(selectedApprover.isInactive() || identityName.equals(selectedApprover.getName())) {
                          Identity identMgr = selectedApprover.getManager();

                          if(identMgr!=null) {
                            thisOwner = identMgr.getName();
                          }
                        }

                        Approval wgApproval = new Approval();
                        ApprovalSet identApprSet = new ApprovalSet();
                        identApprSet.add(ai);
                        wgApproval.setOwner(thisOwner);  
                        wgApproval.setDescription("Identity/wg Level Approval for " +userIdentity.getDisplayName()) ;
                        wgApproval.setApprovalSet(identApprSet);
                        wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
                        wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
                        customApprovals.add(wgApproval);
                      }
                    }
                  }else{
                    //if approvalType is set to Identity but if additionApprover is null, then send the workitem to a standard wg 											
                    Approval wgApproval = new Approval();
                    ApprovalSet identApprSet = new ApprovalSet();
                    identApprSet.add(ai);
                    wgApproval.setOwner(getMinistryWorkgroupName(identityName) );  
                    wgApproval.setDescription("Identity/wg Level Approval for " +userIdentity.getDisplayName()) ;
                    wgApproval.setApprovalSet(identApprSet);
                    wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
                    wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
                    customApprovals.add(wgApproval);

                  }								
                }	
              }							
            }
          } else {
            if (Util.nullSafeEq(launcher, managerName, false) || Util.nullSafeCaseInsensitiveEq(launcher, contractorManagerName) || isManagerApprovalSkip) {
              continue;
            } else if (Util.isNotNullOrEmpty(managerName)) {
              Approval mgrApproval = new Approval();
              ApprovalSet mgrApprSet = new ApprovalSet();
              mgrApprSet.add(ai);
              mgrApproval.setOwner(managerName);  
              mgrApproval.setDescription("Manager Level Approval for " +userIdentity.getDisplayName()) ;
              mgrApproval.setApprovalSet(mgrApprSet);
              mgrApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
              mgrApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
              customApprovals.add(mgrApproval);
            } else {
              Approval mgrApproval = new Approval();
              ApprovalSet mgrApprSet = new ApprovalSet();
              mgrApprSet.add(ai);
              mgrApproval.setOwner(OPERATIONS_WORKGROUP);  
              mgrApproval.setDescription("Manager Level Approval for " +userIdentity.getDisplayName()) ;
              mgrApproval.setApprovalSet(mgrApprSet);
              mgrApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
              mgrApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
              customApprovals.add(mgrApproval);

            }
          }
        }
      } else {
        ManagedAttribute ma = null;
        String FallbackApp = "Cloud IAM Team";
        QueryOptions queryOptions = new QueryOptions();
        queryOptions.addFilter(Filter.eq("application.name", ai.getApplicationName() ));
        queryOptions.addFilter(Filter.eq("value", rName));
        Iterator itr = context.search(ManagedAttribute.class, queryOptions);

        if(itr != null) {
          while(itr.hasNext()) {
            ma = (ManagedAttribute) itr.next();
            break;
          }

          Util.flushIterator(itr);
        }

        if(ma!=null) {
          String approvalType = (String)ma.getAttribute("approvalType");
          logger.debug("approvalType is ::" +approvalType );
          if(Util.isNullOrEmpty(approvalType)){
            approvalType = "manager";
          }
          if(isProvisioningWorkgroup){
            approvalType = "none";
          }

          if(Util.isNotNullOrEmpty(approvalType)) {
            List extraApprover= new ArrayList();
            String[] approvers=approvalType.split(",");
            logger.debug("Approvers are :: " +approvers);

            if(approvers!=null) {
              for(String s : approvers) {

                if(s.equalsIgnoreCase("manager") || s.equalsIgnoreCase("Default")) {
                  if (Util.nullSafeEq(launcher, managerName, false) || Util.nullSafeCaseInsensitiveEq(launcher, contractorManagerName) || isManagerApprovalSkip) {
                    continue;
                  }

                  if (Util.nullSafeEq(launcher, managerName, true) && ai.getApplicationName().equalsIgnoreCase("GSuite")) { // if entitlement/group belongs to GSuite application and requestor is manager of the user(requestee), then skip manager approval
                    continue;
                  }
                  if (Util.isNotNullOrEmpty(managerName) && isManagerActive(identityName)) { //If manager value is not null and if manager is active, get the manager's approval
                    Approval mgrApproval = getManagerApproval(userIdentity, identityName, managerName, ai);
                    customApprovals.add(mgrApproval);
                  } 

                  else if  ( (!(isManagerActive(identityName))) && ai.getApplicationName().equalsIgnoreCase("GSuite") ){ // If the requestee's manager is inactive and the group belongs to GSuite, reassign the approval to the Operations team
                    Approval mgrApproval = new Approval();
                    ApprovalSet mgrApprSet = new ApprovalSet();
                    mgrApprSet.add(ai);
                    mgrApproval.setOwner(OPERATIONS_WORKGROUP);  
                    mgrApproval.setDescription("Manager Level Approval for " +userIdentity.getDisplayName()) ;
                    mgrApproval.setApprovalSet(mgrApprSet);
                    mgrApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
                    mgrApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
                    customApprovals.add(mgrApproval);

                  }

                  else if (isManagersManagerActive(identityName)) {
                    String mgrMgrName = "";
                    Identity userManager = userIdentity.getManager();
                    if (userManager != null && userManager.getManager() != null) {
                      mgrMgrName = userManager.getManager().getName();
                    }
                    Approval mgrMgrApproval = getManagerApproval(userIdentity, identityName, mgrMgrName, ai);
                    customApprovals.add(mgrMgrApproval);
                  } else {
                    Approval mgrApproval = new Approval();
                    ApprovalSet mgrApprSet = new ApprovalSet();
                    mgrApprSet.add(ai);
                    mgrApproval.setOwner(getMinistryWorkgroupName(identityName));  
                    mgrApproval.setDescription("Manager Level Approval for " +userIdentity.getDisplayName()) ;
                    mgrApproval.setApprovalSet(mgrApprSet);
                    mgrApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
                    mgrApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
                    customApprovals.add(mgrApproval);
                  }
                } else if (s.equalsIgnoreCase("owner")) {
                  logger.debug("Entered Owner level approval");
                  Identity roleOwnerCube =  ma.getOwner();
                  if(roleOwnerCube!=null) {
                    String roleOwnerName = roleOwnerCube.getName();
                    Identity selectedApprover = context.getObjectByName(Identity.class, roleOwnerName);
                    String isRoleHighRiskForOwner = (String)ma.getAttribute("privileged");

                    if(roleOwnerCube.isWorkgroup() && "true".equals(isRoleHighRiskForOwner)) {
                      Approval highRiskOwnerApproval = getHighRiskApprovals(roleOwnerCube,ai,identityName,"High Risk Ent Owner");
                      customApprovals.add(highRiskOwnerApproval);
                    }
                    else if(roleOwnerCube.isWorkgroup()) {
                      if (ai.getApplicationName().equalsIgnoreCase("GSuite")) { //If the request is for GSuite group
                        List activeMembers = getWgMembers(selectedApprover); //fetch active members of the approving workgroup
                        logger.debug("Active members of the group are : "+activeMembers);
                        if(activeMembers.size() == 0 ){ //if all members are inactive, assign the approval to the Cloud IAM team
                          Approval wgApproval = new Approval();
                          ApprovalSet identApprSet = new ApprovalSet();
                          identApprSet.add(ai);
                          wgApproval.setOwner(FallbackApp);
                          logger.debug("Owner is : "+roleOwnerCube);
                          wgApproval.setDescription("Owner Level Approval for " +userIdentity.getDisplayName()) ;
                          wgApproval.setApprovalSet(identApprSet);
                          wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
                          wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
                          customApprovals.add(wgApproval);

                        } else {  // if a member of the owner workgroup is active, assign the approval to the owner workgroup
                          Approval wgApproval = new Approval();
                          ApprovalSet identApprSet = new ApprovalSet();
                          identApprSet.add(ai);

                          wgApproval.setOwner(selectedApprover.getName()); 
                          logger.debug("Owner is : "+selectedApprover.getName());
                          wgApproval.setDescription("Owner Level Approval for " +userIdentity.getDisplayName());
                          wgApproval.setApprovalSet(identApprSet);
                          wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
                          wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
                          customApprovals.add(wgApproval);

                        }
                      }
                      else {
                        // check if requester is part of wg and if yes, don't let him to approve his own request
                        Application entApplication = ma.getApplication();
                        Approval wgApproval = getWorkgroupApprovals(roleOwnerCube, ai, entApplication, identityName, "Owner Level Approval");
                        customApprovals.add(wgApproval);
                      } 
                    }else { //if owner is an individual identity, check their status and assign it to them if they are Active or else assign the approval to their manager
                      String thisRoleOwnerName = roleOwnerName;

                      if(!roleOwnerCube.isWorkgroup() && (roleOwnerCube.isInactive()) || identityName.equals(roleOwnerName)) {
                        Identity identMgr = roleOwnerCube.getManager();

                        if(identMgr!=null) { 
                          if (identMgr.isInactive()) { //If the manager's manager is inactive, assign the approval to the Operations team
                            thisRoleOwnerName = OPERATIONS_WORKGROUP;
                          } else {
                            thisRoleOwnerName = identMgr.getName();
                          }
                        }	
                      }

                      Approval ownerApproval = new Approval();
                      ApprovalSet ownerApprSet = new ApprovalSet();
                      ownerApprSet.add(ai);
                      ownerApproval.setOwner(thisRoleOwnerName);  
                      ownerApproval.setDescription("Owner Level Approval for " +userIdentity.getDisplayName()) ;
                      ownerApproval.setApprovalSet(ownerApprSet);
                      ownerApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
                      ownerApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
                      customApprovals.add(ownerApproval);
                    }
                  }
                  else{
                    //if approvalType is set to owner but if owner is null, then send the workitem to a standard wg 

                    Approval ownerApproval = new Approval();
                    ApprovalSet ownerApprSet = new ApprovalSet();
                    ownerApprSet.add(ai);
                    //If entitlement/group belongs to GSuite and owner is not specified in the entitlement attribute, assign the approval to fallback approver group
                    if(ai.getApplicationName().equalsIgnoreCase("GSuite")){
                      ownerApproval.setOwner(FallbackApp);
                    } else {
                      ownerApproval.setOwner(OPERATIONS_WORKGROUP);  
                    } ownerApproval.setDescription("Owner Level Approval for " +userIdentity.getDisplayName()) ;
                    ownerApproval.setApprovalSet(ownerApprSet);
                    ownerApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
                    ownerApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
                    customApprovals.add(ownerApproval);
                  }
                  logger.debug("Exiting owner level approval");
                } else if (s.equalsIgnoreCase("identity")) {
                  logger.debug("Entered third level approval");
                  String approverName = (String) ma.getAttribute("additionalApprover");
                  //  logger.debug("Third level approver is : "+approverName);
                  Identity selectedApprover = context.getObjectByName(Identity.class, approverName);
                  logger.debug("Third level approver is : "+selectedApprover);
                  if(Util.isNotNullOrEmpty(approverName)) {
                    String isRoleHighRiskForAdditional = (String)ma.getAttribute("privilegedIdentity");
                    if(selectedApprover!=null) {
                      if(selectedApprover.isWorkgroup() && "true".equals(isRoleHighRiskForAdditional)) {
                        Approval highRiskwgApproval  = getHighRiskApprovals(selectedApprover,ai,identityName,"Ent Additional Approver");
                        customApprovals.add(highRiskwgApproval);
                      } else if(selectedApprover.isWorkgroup()) {
                        Application entApplication = ma.getApplication();

                        //if the entitlement/group belongs to GSuite and the third level approver is a workgroup(as mentioned in the "additionalApprover" attribute in the entitlement, check the status of all members of the workgroup and if all members are inactive, assign the approval to the Fallback approver group
                        if (ai.getApplicationName().equalsIgnoreCase("GSuite") ) {
                          List activeMembers = getWgMembers(selectedApprover);
                          logger.debug("Active members of the group are :"+activeMembers);
                          if(activeMembers.size() == 0 ){
                            Approval wgApproval = new Approval();
                            ApprovalSet identApprSet = new ApprovalSet();
                            identApprSet.add(ai);
                            wgApproval.setOwner(FallbackApp);
                            logger.debug("Third level approver is : "+selectedApprover.getName());
                            wgApproval.setDescription("Third Level Approval for " +userIdentity.getDisplayName()) ;
                            wgApproval.setApprovalSet(identApprSet);
                            wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
                            wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
                            customApprovals.add(wgApproval);

                          } else {   // if a member of the owner workgroup is active, assign the approval to the owner workgroup
                            Approval wgApproval = getWorkgroupApprovals(selectedApprover, ai, entApplication, identityName, "Third Level");
                            customApprovals.add(wgApproval);
                            logger.debug("Approver is : "+selectedApprover.getName());
                          }
                        }
                      } else {
                        String thisOwner = selectedApprover.getName();

                        if(!selectedApprover.isWorkgroup() && (selectedApprover.isInactive() || identityName.equals(selectedApprover.getName()))) {
                          Identity identMgr = selectedApprover.getManager();

                          if(identMgr!=null) {
                            if (identMgr.isInactive()) {
                              thisOwner = getMinistryWorkgroupName(identityName);
                            } else {
                              thisOwner = identMgr.getName();
                            }
                          }	
                        }	
                        Approval wgApproval = new Approval();
                        ApprovalSet identApprSet = new ApprovalSet();
                        identApprSet.add(ai);
                        wgApproval.setOwner(thisOwner);  
                        wgApproval.setDescription("Identity/wg Approval for " +userIdentity.getDisplayName()) ;
                        wgApproval.setApprovalSet(identApprSet);
                        wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
                        wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
                        customApprovals.add(wgApproval);
                      }
                    }
                    else {
                      //if approvalType is set to Identity but if additionApprover is null, then send the workitem to a standard wg 											
                      Approval wgApproval = new Approval();
                      ApprovalSet identApprSet = new ApprovalSet();
                      identApprSet.add(ai);
                      //if entitlement/group belongs to GSuite and additionalApprover" attribute is blank, assign the approval to Fallback group
                      if(ai.getApplicationName().equalsIgnoreCase("GSuite")){
                        wgApproval.setOwner(FallbackApp);
                        logger.debug("Came to the else for third level");
                        wgApproval.setDescription("Third Level Approval for " +userIdentity.getDisplayName()) ;
                      } else {
                        wgApproval.setOwner( getMinistryWorkgroupName(identityName) );
                        wgApproval.setDescription("Identity/wg Approval for " +userIdentity.getDisplayName()) ; 
                      }
                      wgApproval.setApprovalSet(identApprSet);
                      wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
                      wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
                      customApprovals.add(wgApproval);

                    }		
                  }
                  else {
                    //if approvalType is set to Identity but if additionApprover is null, then send the workitem to a standard wg 											
                    Approval wgApproval = new Approval();
                    ApprovalSet identApprSet = new ApprovalSet();
                    identApprSet.add(ai);
                    //if entitlement/group belongs to GSuite and additionalApprover" attribute is blank, assign the approval to Fallback group
                    if(ai.getApplicationName().equalsIgnoreCase("GSuite")){
                      wgApproval.setOwner(FallbackApp);
                      // logger.debug("Came to the else for third level");
                      wgApproval.setDescription("Third Level Approval for " +userIdentity.getDisplayName()) ;
                    } else {
                      wgApproval.setOwner( getMinistryWorkgroupName(identityName) );
                      wgApproval.setDescription("Identity/wg Approval for " +userIdentity.getDisplayName()) ; 
                    }
                    wgApproval.setApprovalSet(identApprSet);
                    wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
                    wgApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
                    customApprovals.add(wgApproval);

                  }		
                }
              }
            }
          } else {
            if (Util.nullSafeEq(launcher, managerName, false) || Util.nullSafeCaseInsensitiveEq(launcher, contractorManagerName) || isManagerApprovalSkip) {
              continue;
            } else if (Util.isNotNullOrEmpty(managerName)) {
              Approval mgrApproval = new Approval();
              ApprovalSet mgrApprSet = new ApprovalSet();
              mgrApprSet.add(ai);
              mgrApproval.setOwner(managerName);  
              mgrApproval.setDescription("Manager Level Approval for " +userIdentity.getDisplayName()) ;
              mgrApproval.setApprovalSet(mgrApprSet);
              mgrApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
              mgrApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
              customApprovals.add(mgrApproval);
            } else {
              Approval mgrApproval = new Approval();
              ApprovalSet mgrApprSet = new ApprovalSet();
              mgrApprSet.add(ai);
              mgrApproval.setOwner(OPERATIONS_WORKGROUP);  
              mgrApproval.setDescription("Manager Level Approval for " +userIdentity.getDisplayName()) ;
              mgrApproval.setApprovalSet(mgrApprSet);
              mgrApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_CLASS, "sailpoint.object.Identity");
              mgrApproval.addArg(Workflow.ARG_WORK_ITEM_TARGET_NAME, identityName);
              customApprovals.add(mgrApproval);
            }
          }
        }
      }


      if(customApprovals.size()>0) {

        Approval setItemToChildrenApproval = new Approval();
        setItemToChildrenApproval.setChildren(customApprovals);
        setItemToChildrenApproval.setMode("serial");
        logger.debug("setItemToChildrenApproval formed is ::" + setItemToChildrenApproval);
        finalApprovals.add(setItemToChildrenApproval);

      }
    }  
  }		

  // Auto approve the roles of approvalType 'none'
  if(finalApprovals != null && finalApprovals.isEmpty()) {
    List items = approvalSet.getItems();

    if(items!=null && items.size()>0) {
      for(ApprovalItem item :items ) {
        item.setState(WorkItem.State.Finished);
      }
      logger.debug("verified none approval and setted the state");
    }
  }
  logger.debug("final approvals before superapprovals :::  "+finalApprovals);

  if(finalApprovals!= null && finalApprovals.size()>0) {
    Approval superApproval = new Approval();
    superApproval.setChildren(finalApprovals);
    superApproval.setMode("parallel");
    superApprovals.add(superApproval);
  }


  logger.debug("Exiting " +RULE_NAME);  
  return superApprovals;
